1	// Pins the contract of HandoffSite + compute_handoff_pc, which the QEMU TCG
2	// plugin uses to compute the post-trigger resume PC without reading the
3	// architectural PC register at run time. Reading PC via the gdbstub layer
4	// inside an exec callback returns a stale value when V instructions retire
5	// just before the trigger (TCG defers PC writes); capturing vaddr/size at
6	// translate time avoids the lag entirely.
7	
8	#include "hybrid/handoff_site.h"
9	#include "hybrid/insn_match.h"
10	
11	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
12	#include <doctest.h>
13	
14	#include <cstdint>
15	
16	TEST_CASE("compute_handoff_pc returns vaddr + size for a 4-byte trigger")
17	{
18	  const HandoffSite site{HYBRID_HANDOFF_ENTER, 0x80001234ULL, 4u};
19	  CHECK(compute_handoff_pc(&site) == 0x80001238ULL);
20	}
21	
22	TEST_CASE("compute_handoff_pc honors a compressed (2-byte) trigger")
23	{
24	  // PC-mode allows a fixture to park _hybrid_enter_pc on a compressed insn.
25	  const HandoffSite site{HYBRID_HANDOFF_ENTER, 0x80002000ULL, 2u};
26	  CHECK(compute_handoff_pc(&site) == 0x80002002ULL);
27	}
28	
29	TEST_CASE("HandoffSite preserves the kind across the trans -> exec hop")
30	{
31	  const HandoffSite enter{HYBRID_HANDOFF_ENTER,   0x1000ULL, 4u};
32	  const HandoffSite exit_{HYBRID_HANDOFF_EXIT,    0x2000ULL, 4u};
33	  const HandoffSite rt   {HYBRID_HANDOFF_RUNTIME, 0x3000ULL, 4u};
34	  CHECK(enter.kind == HYBRID_HANDOFF_ENTER);
35	  CHECK(exit_.kind == HYBRID_HANDOFF_EXIT);
36	  CHECK(rt.kind    == HYBRID_HANDOFF_RUNTIME);
37	}
