1	/* Trap glue shared by all C-level round-trip fixtures.
2	 *
3	 * crt0.S invokes init_mtvec() as a constructor; trap.S's m_trap_entry
4	 * tail-calls handle_trap on every exception or interrupt. libgloss_vh
5	 * routes syscalls through the RISC-V semihosting magic triple, not
6	 * through `ecall`, so there's no syscall-dispatch table here. Any trap
7	 * is treated as a fatal error: print a diagnostic and exit.
8	 */
9	
10	#ifdef __cplusplus
11	extern "C"
12	{
13	#endif
14	
15	#include <stdint.h>
16	#include <stdio.h>
17	
18	#define WRITE_ERROR(format, ...) \
19	  fprintf(stderr, "\033[31m[ERROR] " format "\033[0m\n", ##__VA_ARGS__)
20	
21	__attribute__((used, noreturn)) void _exit(int exit_status);
22	
23	void exception_handler(void)
24	{
25	  uint32_t mcause, mdcause, mepc, mtval;
26	
27	  asm volatile("csrr %0, mcause" : "=r"(mcause));
28	  asm volatile("csrr %0, mdcause" : "=r"(mdcause));
29	  asm volatile("csrr %0, mepc" : "=r"(mepc));
30	  asm volatile("csrr %0, mtval" : "=r"(mtval));
31	
32	  WRITE_ERROR("Trap occurred!");
33	  WRITE_ERROR("mcause: 0x%x", mcause);
34	  WRITE_ERROR("mdcause: 0x%x", mdcause);
35	  WRITE_ERROR("mepc: 0x%x", mepc);
36	  WRITE_ERROR("mtval: 0x%x", mtval);
37	
38	  if ((mcause & 0x80000000) == 0) {
39	    WRITE_ERROR("Exception code: %d", mcause);
40	  } else {
41	    WRITE_ERROR("Interrupt occurred! Cause: %d", mcause & 0x7FFFFFFF);
42	  }
43	
44	  _exit(mcause);
45	}
46	
47	void handle_trap(unsigned long cause, void* tf)
48	{
49	  (void) cause;
50	  (void) tf;
51	  exception_handler();
52	}
53	
54	extern void m_trap_entry(void);
55	
56	__attribute__((constructor)) void init_mtvec(void)
57	{
58	  uintptr_t handler_address = (uintptr_t) &m_trap_entry;
59	  asm volatile("csrw mtvec, %0" : : "r"(handler_address));
60	}
61	
62	#ifdef __cplusplus
63	}
64	#endif
